CREATE OR REPLACE FUNCTION fpa_com_fee_bank_tmb_kept (as_bank_accno char ) RETURNS bigint AS $body$
DECLARE

 ls_brnach sc_acc_m_ucf_bank_branch.bank_branch_id%type;
 ls_cheque_code sc_acc_m_ucf_bank_branch.cheque_code%type;
 ldc_number bigint;

BEGIN  --ใช้เฉพาะการส่งแผ่นของธนาคารทหารไทย ที่ สอ.นย. เท่านั้น
 ls_brnach :=  substr(trim(both as_bank_accno),1,3);
  begin
   select cheque_code into STRICT ls_cheque_code
   from   sc_acc_m_ucf_bank_branch
   where (bank_branch_id = ls_brnach  )
   and (bank_id = '11');
  Exception
   when no_data_found then ls_cheque_code := '3';
   when others then CALL spa_dberror('E15 : หาธนาคารไม่พบ');
  end;
 if ls_cheque_code = '2' then
    ldc_number := 10;
 else
    ldc_number := 30;
 end if;

 return ldc_number;
Exception
 when others then CALL spa_dberror('FPA_COM_FEE_BANK_TMB_KEPT');

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
